export class ProfileModel {
    title: string;
    emp_id: string;
    tel: string;
    fax: string;
    cell: string;
    e_sign: string;
    pic: string;
    wallpaper: string;
    stamp: string;
    bio: string;
    location: string;
    birth_date: Date;


    constructor(profile: ProfileModel) {
        this.title = profile.title;
        this.emp_id = profile.emp_id;
        this.tel = profile.tel;
        this.fax = profile.fax;
        this.cell = profile.cell;
        this.e_sign = profile.e_sign;
        this.pic = profile.pic;
        this.wallpaper = profile.wallpaper;
        this.stamp = profile.stamp;
        this.bio = profile.bio;
        this.location = profile.location;
        this.birth_date = new Date(profile.birth_date);
    }
}
