import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';


@Injectable({
    providedIn: 'root'
})
export class ApiHttpService {
    private readonly ApiHost: string = '/api';


    constructor(private httpClient: HttpClient) {
    }

    public request(method: string, endpoint: string, body?: any, reqOpts: any = {}, withCredentials: boolean = true): Observable<any> {
        if (withCredentials) {
            reqOpts.withCredentials = withCredentials;
        }
        if (body) {
            reqOpts.body = body;
        }
        return this.httpClient.request(method, this.ApiHost + endpoint, reqOpts);
    }

    public get(endpoint: string, reqOpts: any = {}, params: any = undefined, withCredentials: boolean = true): Observable<any> {
        if (params) {
            let httpParams = new HttpParams();
            for (const key in params) {
                if (params.hasOwnProperty(key)) {
                    httpParams = httpParams.set(key, params[key]);
                }
            }
            reqOpts.params = httpParams;
        }

        if (withCredentials) {
            reqOpts.withCredentials = withCredentials;
        }

        return this.httpClient.get(this.ApiHost + endpoint, reqOpts);
    }

    public post(endpoint: string, body: any, reqOpts: any = {}, withCredentials: boolean = true): Observable<any> {
        if (withCredentials) {
            reqOpts.withCredentials = withCredentials;
        }
        return this.httpClient.post(this.ApiHost + endpoint, body, reqOpts);
    }

    public put(endpoint: string, body: any, reqOpts: any = {}, withCredentials: boolean = true): Observable<any> {
        if (withCredentials) {
            reqOpts.withCredentials = withCredentials;
        }
        return this.httpClient.put(this.ApiHost + endpoint, body, reqOpts);
    }

    public delete(endpoint: string, reqOpts: any = {}, withCredentials: boolean = true): Observable<any> {
        if (withCredentials) {
            reqOpts.withCredentials = withCredentials;
        }
        return this.httpClient.delete(this.ApiHost + endpoint, reqOpts);
    }

    public patch(endpoint: string, body: any, reqOpts: any = {}, withCredentials: boolean = true): Observable<any> {
        if (withCredentials) {
            reqOpts.withCredentials = withCredentials;
        }
        return this.httpClient.patch(this.ApiHost + endpoint, body, reqOpts);
    }
}
