export class ProjectModel {
    id: number;
    name: string;
    address_line_1: string;
    city: string;
    state: string;
    zip: string;
    created_on: Date;
    estimator: string;
    tech: string;
    passedSteps: number;

    constructor(project: ProjectModel) {
        this.id = project.id;
        this.name = project.name;
        this.address_line_1 = project.address_line_1;
        this.city = project.city;
        this.state = project.state;
        this.zip = project.zip;
        this.created_on = new Date(project.created_on);
        this.estimator = project.estimator;
        this.tech = project.tech;
        this.passedSteps = project.passedSteps;
    }
}
